PRAGMA foreign_keys=ON;
CREATE TABLE cluster(cluster_id INTEGER PRIMARY KEY,name TEXT,description TEXT);
CREATE TABLE stakeholder(stakeholder_id INTEGER PRIMARY KEY,full_name TEXT,email TEXT,phone TEXT,is_active INTEGER,created_at TEXT);
CREATE TABLE role(role_id INTEGER PRIMARY KEY,role_key TEXT,role_name TEXT);
CREATE TABLE property(property_id INTEGER PRIMARY KEY,unit_code TEXT,display_name TEXT,address_line_1 TEXT,city TEXT,state_province TEXT,postal_code TEXT,wifi_ssid TEXT,wifi_password_ciphertext TEXT,wifi_password_secret_ref TEXT,door_code_ciphertext TEXT,door_code_secret_ref TEXT,qc_assignee_stakeholder_id INTEGER,standing_instructions TEXT,cluster_id INTEGER,roster_active INTEGER,source_system TEXT,created_at TEXT,updated_at TEXT);
CREATE TABLE stakeholder_role(stakeholder_role_id INTEGER PRIMARY KEY,stakeholder_id INTEGER,role_id INTEGER,property_id INTEGER,created_at TEXT);
CREATE TABLE stage_definition(stage_definition_id INTEGER PRIMARY KEY,stage_key TEXT,stage_name TEXT,display_order INTEGER,is_active INTEGER);
CREATE TABLE task(task_id INTEGER PRIMARY KEY,property_id INTEGER,arrival_date TEXT,assigned_housekeeper_stakeholder_id INTEGER,current_stage_definition_id INTEGER,source_row_number INTEGER,source_system TEXT,created_at TEXT,updated_at TEXT);
CREATE TABLE task_stage_event(stage_event_id INTEGER PRIMARY KEY,task_id INTEGER,stage_definition_id INTEGER,is_complete INTEGER,completed_at TEXT,completed_by_stakeholder_id INTEGER,source_value TEXT);
CREATE TABLE checklist_template(checklist_template_id INTEGER PRIMARY KEY,template_name TEXT,version_label TEXT,is_active INTEGER,created_at TEXT);
CREATE TABLE checklist_category(checklist_category_id INTEGER PRIMARY KEY,checklist_template_id INTEGER,category_name TEXT,display_order INTEGER);
CREATE TABLE checklist_item_template(checklist_item_template_id INTEGER PRIMARY KEY,checklist_category_id INTEGER,item_text TEXT,display_order INTEGER,required_photo INTEGER,maintenance_required INTEGER);
CREATE TABLE inspection(inspection_id INTEGER PRIMARY KEY,task_id INTEGER,checklist_template_id INTEGER,inspector_stakeholder_id INTEGER,started_at TEXT,submitted_at TEXT);
CREATE TABLE inspection_item_result(inspection_item_result_id INTEGER PRIMARY KEY,inspection_id INTEGER,checklist_item_template_id INTEGER,result TEXT,photo_memory_id INTEGER,notes TEXT,observed_at TEXT,inspector_stakeholder_id INTEGER);
CREATE TABLE photo_memory(photo_memory_id INTEGER PRIMARY KEY,property_id INTEGER,task_id INTEGER,inspection_id INTEGER,uri TEXT,storage_ref TEXT,content_hash TEXT,caption TEXT,captured_at TEXT,metadata_json TEXT);
CREATE TABLE inspection_reports(form_uuid TEXT PRIMARY KEY,created_utc TEXT,updated_utc TEXT,property TEXT,signed_off INTEGER,items_total INTEGER,items_done INTEGER,sections INTEGER,repairs TEXT,state_json TEXT,html_bytes INTEGER,archived_utc TEXT,s3_summary_uri TEXT,s3_artifact_uri TEXT);

